import{_ as a,o as t,c as n,j as r,a as p,a1 as b}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"黄金猎犬","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/黄金猎犬.md","filePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/黄金猎犬.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/6.可升级/黄金猎犬.md"};function s(d,e,l,h,_,i){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"黄金猎犬",tabindex:"-1"},[p("黄金猎犬 "),r("a",{class:"header-anchor",href:"#黄金猎犬","aria-label":'Permalink to "黄金猎犬"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),b('<h1 id="黄金猎犬-1" tabindex="-1">黄金猎犬 <a class="header-anchor" href="#黄金猎犬-1" aria-label="Permalink to &quot;黄金猎犬&quot;">​</a></h1><p>黄金猎犬The Golden Hounds<br> D+1000<br> 本质：魔幻本质<br> 分类：鞋袜<br> 在乔伊斯·兰斯年轻的时候，骑兵袭击了他的村庄。由于无法战斗，他的父母和邻居都死于非命，或是身受重伤。她带着自己年幼的弟弟桑德逃出了村子，随着剧烈的心跳声将追击者抛在身后。几年后，当得知桑德的商队遭到妖邪袭击时，乔伊斯·兰斯奔行千里去营救他，但当俘虏他的人进入洪荒之后，她失去了弟弟的踪迹。自此之后，乔伊斯再也撑不住了。<br> 她从道路之神鲁维亚那骗来了他永不停歇的凉鞋，将它们锻造成了神金靴子的鞋底，可以越过任何地方，追踪任何人。就这样，她消失在了洪荒里，去救她的弟弟。<br> 这双神金之靴光滑而锐利，在运动时会闪烁光芒。当穿着者移动时会迸发出一连串火花，黄金猎犬免疫无支线等级的环境地形。</p><p>特性：【黄金猎犬的号令】、【流光奔袭】</p><p>黄金猎犬的号令<br> 黄金猎犬的力量是速度。每当穿戴者在一回合内最少移动44+迅捷层数*5米的距离，他便可获得一层迅捷，人物获得的迅捷层数上限为自身的敏捷属性值，每一层迅捷都会为穿戴者提供额外5米的移动速度（即获得迅捷层数*5米的移动速度）。这些迅捷层数将持续一个场景。<br> 注意，以下情况可能导致迅捷层数提前归0：<br> 如果人物上一个回合没有移动到最低距离，则迅捷层数重置为0。<br> 若人物在本回合内，收到某种降低移动速度的效果，则迅捷层数-1。<br> 迅捷层数最低为0，减值可叠加。</p><p>流光奔袭<br> 黄金猎犬仍然记得乔伊斯·兰斯横跨洪荒的追猎，只要穿戴者保持奔跑，便犹如流光。<br> 人物花费10个整轮向着一个方向开始全力奔跑，感受速度与风的呼号，在该奔跑过程中，黄金猎犬迸发出的火花将在人物的身后形成一条淡金色的光带,并使得人物的速度逐渐增加，当到第11轮时，人物的地面移动速度增加到300km/h，在该状态下，人物失去基础和闪避防御，所有的动作都必须用来专心的维持奔跑，机动性下降为笨拙。在奔跑期间，人物受到任何伤害都会导致穿戴者立即退出流光奔袭，并进行一次DC=伤害数的敏捷鉴定，若失败则陷入倒地。<br> 流光奔袭仅能在地面上奔跑，这导致人物起点到目的地之间，需有确实可行的地面道路<br> 一旦流光奔袭启动完毕，人物想要退出流光奔袭便需要花费3个整轮减速，这是D级旅行效果。</p><p>逐级升级：<br> 黄金猎犬The Golden Hounds<br> C+1500）<br> 在D级物品效果的基础上，额外获得以下特性。<br> 闪光冲袭：<br> 当高速移动时，人物逐渐高涨的速度将化作磅礴的冲量，每轮一次，人物可在攻击中无需消费动作的结合一次【冲撞】，人物的冲撞检定将获得等同于迅捷层数的增强加值。</p><p>流光奔袭（提升）<br> 当人物展开流光奔袭长途旅行时，其最高速度提升到1000km/h，其他限制不变，这是C级旅行效果。</p><p>逐级升级：<br> 黄金猎犬The Golden Hounds<br> B+2500<br> 在D、C级物品的基础上，额外获得以下特性。</p><p>黄金猎犬的号令（提升）<br> 人物使用黄金猎犬的号令时，每层迅捷层数提升的速度变为20米,且每层迅捷层数还将提供1点闪避防御加值。<br> 人物的每轮的最低移动速度变为44+迅捷层数*20米的距离，其余限制不变。</p><p>-赴死夺人<br> 黄金猎犬是为了救助他人锻造的，若在回合外人物还具有足以移动的AP，可以反射动作转化出移动动作并进行一次移动，移动的最大距离等于人物的最大移动距离。若人物在回合内未使用C级提供的冲撞效果，则在本次移动中，可以选择触及范围内的一名正在进行攻击的敌人使用冲撞撞开，则该次冲撞具有【打断性】，并将那次攻击的目标转为自身重新结算，这是一个B级创伤来源的胁迫效果。</p><p>流光奔袭-闪电音速（提升）<br> 当人物展开流光奔袭长途旅行时，其最高速度可抵达两倍音速，最高速提升到2288km/h，同时与目标之间无需确实可行地面道路，只需拥有到达目的的路径便可，其他限制不变，这是B级旅行效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const f=a(o,[["render",s]]);export{m as __pageData,f as default};
